function panel(title,cls){const el=document.createElement('section');el.className=`pr-panel ${cls}`;el.innerHTML=`<div class="pr-panel-title">${title}</div>`;return el}
function ensureLayout(){const root=document.getElementById('assemblyTimeline');if(!root||root.closest('.premiere-editor'))return;const shell=document.createElement('div');shell.className='premiere-editor';shell.id='premiereEditor';root.parentNode.insertBefore(shell,root);const project=panel('プロジェクト','pr-project'),program=panel('プログラム','pr-program'),props=panel('プロパティ','pr-properties'),timeline=panel('タイムライン','pr-timeline-panel');project.innerHTML+='<input class="pr-search" id="prAssetSearch" type="search" placeholder="素材を検索"><div id="prAssetBin"></div>';props.innerHTML+='<div class="pr-properties-body" id="prProperties"><div class="pr-empty">タイムラインでクリップを選択してください</div></div>';timeline.innerHTML+='<nav class="pr-tool-rail" aria-label="タイムラインツール"><button type="button" data-tool="select" class="active" title="選択">選択</button><button type="button" data-tool="split" title="分割">分割</button><button type="button" data-tool="zoom-in" title="拡大">拡大</button><button type="button" data-tool="zoom-out" title="縮小">縮小</button><button type="button" data-tool="fit" title="全体表示">全体</button></nav><div class="pr-timeline-main" id="prTimelineMain"></div><aside class="pr-meter" aria-label="音量メーター"><div class="pr-meter-track"><i class="pr-meter-level" id="prMeterLevel"></i></div></aside>';const r1=document.createElement('i'),r2=document.createElement('i'),rh=document.createElement('i');r1.className='pr-resizer pr-resizer-v pr-project-resizer';r2.className='pr-resizer pr-resizer-v pr-properties-resizer';rh.className='pr-resizer pr-resizer-h';shell.append(project,r1,program,r2,props,rh,timeline);document.getElementById('prTimelineMain').append(root);bindResize(shell,r1,'project');bindResize(shell,r2,'properties');bindResize(shell,rh,'height');document.getElementById('prAssetSearch').addEventListener('input',renderAssets);timeline.addEventListener('dragover',e=>e.preventDefault());timeline.addEventListener('drop',dropAsset);timeline.querySelector('.pr-tool-rail').addEventListener('click',toolClick)}
const transportSvg={home:'<svg viewBox="0 0 20 20" aria-hidden="true"><path d="M4 4v12M16 5 7 10l9 5z"/></svg>',previous:'<svg viewBox="0 0 20 20" aria-hidden="true"><path d="M3 4h2v12H3zm13 1-9 5 9 5z"/></svg>',play:'<svg viewBox="0 0 20 20" aria-hidden="true"><path d="m6 4 10 6-10 6z"/></svg>',pause:'<svg viewBox="0 0 20 20" aria-hidden="true"><path d="M6 4h3v12H6zm5 0h3v12h-3z"/></svg>',stop:'<svg viewBox="0 0 20 20" aria-hidden="true"><path d="M5 5h10v10H5z"/></svg>',next:'<svg viewBox="0 0 20 20" aria-hidden="true"><path d="m4 5 9 5-9 5zm11-1h2v12h-2z"/></svg>',end:'<svg viewBox="0 0 20 20" aria-hidden="true"><path d="M16 4v12M4 5l9 5-9 5z"/></svg>'};
const programTotal=()=>Math.max(0,Number(_atlModel?.total_duration)||0);
function seekFromPointer(event,bar){const rect=bar.getBoundingClientRect(),total=programTotal();if(rect.width)window.atlSetPosition?.(Math.max(0,Math.min(total,(event.clientX-rect.left)/rect.width*total)))}
function bindProgramSeek(bar){bar.addEventListener('pointerdown',e=>{if(e.button!==0)return;e.preventDefault();bar.setPointerCapture?.(e.pointerId);seekFromPointer(e,bar);const move=ev=>seekFromPointer(ev,bar),up=()=>{bar.removeEventListener('pointermove',move);bar.removeEventListener('pointerup',up);bar.removeEventListener('pointercancel',up)};bar.addEventListener('pointermove',move);bar.addEventListener('pointerup',up,{once:true});bar.addEventListener('pointercancel',up,{once:true})})}
function ensureProgramStrip(program){let strip=program.querySelector('.pr-program-strip');if(strip)return;strip=document.createElement('div');strip.className='pr-program-strip';strip.innerHTML=`<div class="pr-program-seek" data-program-seek role="slider" tabindex="0" aria-label="プレビューの再生位置" aria-valuemin="0" aria-valuenow="0"><i></i><b></b></div><div class="pr-program-row"><span class="pr-program-current" data-program-clock-slot></span><div class="pr-program-transport" aria-label="プレビュー操作"><button type="button" data-program-home title="先頭へ" aria-label="先頭へ">${transportSvg.home}</button><button type="button" data-program-previous title="前の曲境界へ" aria-label="前の曲境界へ">${transportSvg.previous}</button><button type="button" data-atl-play title="再生" aria-label="再生" aria-pressed="false">${transportSvg.play}</button><button type="button" data-program-next title="次の曲境界へ" aria-label="次の曲境界へ">${transportSvg.next}</button><button type="button" data-program-end title="末尾へ" aria-label="末尾へ">${transportSvg.end}</button><button type="button" data-atl-stop class="pr-program-stop" title="停止" aria-label="停止">${transportSvg.stop}</button></div><code class="pr-program-duration" data-program-duration>00:00:00</code></div>`;program.append(strip);const clock=document.getElementById('atlPreviewClock'),slot=strip.querySelector('[data-program-clock-slot]');if(clock&&slot)slot.append(clock);strip.querySelector('[data-program-home]').onclick=()=>window.atlSetPosition?.(0);strip.querySelector('[data-program-previous]').onclick=()=>window.atlBoundary?.(-1);strip.querySelector('[data-atl-play]').onclick=()=>window.atlToggleFilmora?.();strip.querySelector('[data-atl-stop]').onclick=()=>window.atlStopFilmora?.();strip.querySelector('[data-program-next]').onclick=()=>window.atlBoundary?.(1);strip.querySelector('[data-program-end]').onclick=()=>window.atlSetPosition?.(programTotal());bindProgramSeek(strip.querySelector('[data-program-seek]'));bindVisualizerCanvas();updateProgramStrip(Number(_atlPlayhead)||0)}
function updateProgramStrip(sec){const total=programTotal(),ratio=total?Math.max(0,Math.min(1,(Number(sec)||0)/total)):0,bar=document.querySelector('[data-program-seek]'),duration=document.querySelector('[data-program-duration]');if(bar){bar.style.setProperty('--program-progress',`${ratio*100}%`);bar.setAttribute('aria-valuemax',String(total));bar.setAttribute('aria-valuenow',String(Math.max(0,Number(sec)||0)))}if(duration)duration.textContent=typeof atlTime==='function'?atlTime(total):'00:00:00'}
function placePreview(){const preview=document.getElementById('atlPreview'),program=document.querySelector('.pr-program');if(!program)return;if(preview&&!program.contains(preview))program.append(preview);ensureProgramStrip(program);const strip=program.querySelector('.pr-program-strip');if(strip&&program.lastElementChild!==strip)program.append(strip)}
async function loadAssets(){if(!_curVideo||!_atlModel)return;try{const d=await fetch(`/api/timeline/${encodeURIComponent(_curVideo)}/image-candidates`).then(r=>r.json());P.images=d.images||[]}catch{P.images=[]}renderAssets();hydrateImageSizes()}
function renderAssets(){const bin=document.getElementById('prAssetBin');if(!bin||!_atlModel)return;const q=(document.getElementById('prAssetSearch')?.value||'').trim().toLowerCase(),audio=(_atlModel.audio_clips||[]).filter(x=>!q||String(x.filename).toLowerCase().includes(q)),images=P.images.filter(x=>!q||String(x.name).toLowerCase().includes(q));bin.innerHTML=`<div class="pr-bin-group-title">楽曲</div>${audio.map(x=>`<div class="pr-asset" draggable="true" data-kind="audio" data-id="${esc(x.id)}" title="ダブルクリックで試聴"><span class="pr-asset-kind">音声</span><span class="pr-asset-name">${esc(x.filename)}</span><span class="pr-asset-meta">${fmt(x.duration)}</span></div>`).join('')}<div class="pr-bin-group-title">画像</div>${images.map(x=>`<div class="pr-asset" draggable="true" data-kind="image" data-path="${esc(x.path)}" title="ダブルクリックでプレビュー"><img class="pr-asset-thumb" src="${x.url}" alt=""><span class="pr-asset-name">${esc(x.name)}</span><span class="pr-asset-meta">画像</span></div>`).join('')}`;bin.querySelectorAll('.pr-asset').forEach(el=>{el.addEventListener('dragstart',assetDrag);el.addEventListener('dblclick',assetPreview)})}
function hydrateImageSizes(){document.querySelectorAll('.pr-asset[data-kind="image"]').forEach(async el=>{const img=el.querySelector('img'),meta=el.querySelector('.pr-asset-meta');if(!img||!meta)return;try{const r=await fetch(img.src,{method:'HEAD'}),n=Number(r.headers.get('content-length')||0);if(n)meta.textContent=n>=1048576?`${(n/1048576).toFixed(1)} MB`:`${Math.ceil(n/1024)} KB`}catch{}})}
function assetDrag(e){e.dataTransfer.effectAllowed='copy';e.dataTransfer.setData('application/x-orzz-asset',JSON.stringify({kind:e.currentTarget.dataset.kind,id:e.currentTarget.dataset.id||'',path:e.currentTarget.dataset.path||''}))}
function assetPreview(e){const el=e.currentTarget;if(el.dataset.kind==='audio'){const c=_atlModel.audio_clips.find(x=>x.id===el.dataset.id);if(c)window.atlPlayAt(c.start||0)}else{const img=document.getElementById('atlPreviewImage');if(img){P.previewImage=img.src;img.src=`/api/timeline/${encodeURIComponent(_curVideo)}/image?path=${encodeURIComponent(el.dataset.path)}`}}}
function dropAsset(e){const raw=e.dataTransfer.getData('application/x-orzz-asset');if(!raw)return;e.preventDefault();const item=JSON.parse(raw),before=clone(_atlModel);if(item.kind==='audio'){const source=_atlModel.audio_clips.find(x=>x.id===item.id);if(!source)return;const copy={...clone(source),id:`${source.id}-${Date.now()}`};_atlModel.audio_clips.push(copy)}else{const hit=e.target.closest('.atl-visual'),index=hit?Array.from(document.querySelectorAll('.atl-visual')).indexOf(hit):-1;if(index>=0)_atlModel.visual_segments[index].image_path=item.path;else{const start=Math.max(0,Math.min(Number(_atlPlayhead)||0,Number(_atlModel.total_duration)||0)),end=Math.min(Number(_atlModel.total_duration)||start+5,start+5);_atlModel.visual_segments.push({id:`visual-${Date.now()}`,image_path:item.path,start,end,crossfade_sec:0});_atlModel.visual_segments.sort((a,b)=>a.start-b.start)}}window.atlCommit(before)}
function spectrumMarkup(){return ''}
const TEXT_POSITIONS=[['top-left','左上'],['top-center','上中央'],['top-right','右上'],['middle-left','左中央'],['center','中央'],['middle-right','右中央'],['bottom-left','左下'],['bottom-center','下中央'],['bottom-right','右下']];
const finite=(value,fallback=0)=>value!==null&&value!==''&&Number.isFinite(Number(value))?Number(value):fallback;
const attr=value=>esc(value).replace(/"/g,'&quot;').replace(/'/g,'&#39;');
const colorValue=(value,fallback)=>/^#[0-9a-f]{6}$/i.test(String(value||''))?String(value):fallback;
function resolveSelection(sel){if(!sel)return null;if(sel.kind==='audio'){const row=(_atlModel.audio_clips||[]).find(x=>x.id===sel.id);return row?{kind:'audio',label:'音声',name:row.filename||row.id,row}:null}if(sel.kind==='visual'){const row=(_atlModel.visual_segments||[])[Number(sel.index)];return row?{kind:'visual',label:'映像',name:row.image_path||row.id,row}:null}if(sel.kind==='free-text'){const track=(_atlModel.text_tracks||[]).find(x=>x.id===sel.trackId),row=track?.clips?.[Number(sel.index)];return row?{kind:'text',label:'文字',name:row.text||row.id,row,track}:null}return null}
function commonProperties(item){const row=item.row,start=finite(row.start),end=finite(row.end,start+finite(row.duration)),duration=Math.max(0,end-start),readOnly=item.kind==='audio'?' readonly aria-readonly="true"':'';return `<div class="pr-prop-row"><span>種類</span><strong>${item.label}</strong></div><div class="pr-prop-row"><span>名前</span><span title="${attr(item.name)}">${esc(item.name)}</span></div><div class="pr-prop-row"><span>開始</span><input data-prop="start" type="number" step="0.1" value="${start}"${readOnly}></div><div class="pr-prop-row"><span>終了</span><input data-prop="end" type="number" step="0.1" value="${end}"${readOnly}></div><div class="pr-prop-row"><span>尺</span><output data-duration-output>${duration.toFixed(2)} 秒</output></div>`}
function transitionProperties(row){return `<div class="pr-prop-row"><span>クロスフェード</span><input data-prop="crossfade_sec" type="number" min="0" max="10" step="0.1" value="${Math.max(0,finite(row.crossfade_sec))}"></div><div class="pr-prop-row"><span>繋ぎ</span><select data-prop="crossfade_curve"><option value="equal_power" ${row.crossfade_curve==='equal_power'?'selected':''}>等パワー</option><option value="linear" ${row.crossfade_curve==='linear'?'selected':''}>リニア</option></select></div>`}
function textProperties(row){const position=row.position||'center';return `<div class="pr-prop-row"><span>テキスト</span><textarea data-prop="text">${esc(row.text||'')}</textarea></div><div class="pr-prop-row"><span>フォントパス</span><input data-prop="font_path" value="${attr(row.font_path||'')}"></div><div class="pr-prop-row"><span>フォント名</span><input data-prop="font_name" value="${attr(row.font_name||'Hiragino Sans')}"></div><div class="pr-prop-row"><span>位置</span><select data-prop="position">${TEXT_POSITIONS.map(([value,label])=>`<option value="${value}" ${position===value?'selected':''}>${label}</option>`).join('')}</select></div><div class="pr-prop-row"><span>サイズ</span><input data-prop="size" type="number" min="1" step="1" value="${Math.max(1,finite(row.size,48))}"></div><div class="pr-prop-row"><span>文字色</span><input data-prop="color" type="color" value="${colorValue(row.color,'#ffffff')}"></div><div class="pr-prop-row"><span>縁取り色</span><input data-prop="border_color" type="color" value="${colorValue(row.border_color,'#000000')}"></div><div class="pr-prop-row"><span>縁取り</span><input data-prop="border_width" type="number" min="0" step="1" value="${Math.max(0,finite(row.border_width,2))}"></div><div class="pr-prop-row"><span>不透明度</span><input data-prop="opacity" type="number" min="0" max="1" step="0.05" value="${Math.max(0,Math.min(1,finite(row.opacity,1)))}"></div><div class="pr-prop-row"><span>フェードイン</span><input data-prop="fade_in" type="number" min="0" step="0.1" value="${Math.max(0,finite(row.fade_in,.4))}"></div><div class="pr-prop-row"><span>フェードアウト</span><input data-prop="fade_out" type="number" min="0" step="0.1" value="${Math.max(0,finite(row.fade_out,.4))}"></div><div class="pr-prop-row"><span>余白</span><input data-prop="margin" type="number" min="0" step="1" value="${Math.max(0,finite(row.margin,64))}"></div>`}
function visualizerForm(){const v=_atlModel.visualizer||{},pattern=v.pattern||'bars',position=v.position||'bottom-center';return `<div class="pr-prop-row"><span>表示</span><input data-visualizer="enabled" type="checkbox" ${v.enabled?'checked':''}></div><div class="pr-prop-row"><span>パターン</span><select data-visualizer="pattern"><option value="bars" ${pattern==='bars'?'selected':''}>バー</option><option value="mirror" ${pattern==='mirror'?'selected':''}>ミラーバー</option><option value="wave" ${pattern==='wave'?'selected':''}>波形ライン</option><option value="circle" ${pattern==='circle'?'selected':''}>円形</option></select></div><div class="pr-prop-row"><span>位置</span><select data-visualizer="position">${TEXT_POSITIONS.map(([value,label])=>`<option value="${value}" ${position===value?'selected':''}>${label}</option>`).join('')}</select></div><div class="pr-prop-row"><span>幅</span><div class="atl-unit-field"><input data-visualizer="width_percent" type="number" min="10" max="100" step="1" value="${finite(v.width_percent,72)}"><span>%</span></div></div><div class="pr-prop-row"><span>高さ</span><div class="atl-unit-field"><input data-visualizer="height_px" type="number" min="20" max="1080" step="1" value="${finite(v.height_px,180)}"><span>px</span></div></div><div class="pr-prop-row"><span>余白</span><div class="atl-unit-field"><input data-visualizer="margin" type="number" min="0" max="500" step="1" value="${finite(v.margin,64)}"><span>px</span></div></div><div class="pr-prop-row"><span>色1</span><input data-visualizer="color" type="color" value="${colorValue(v.color,'#ffffff')}"></div><div class="pr-prop-row"><span>色2</span><input data-visualizer="color2" type="color" value="${colorValue(v.color2,'#65bfff')}"></div><div class="pr-prop-row"><span>不透明度</span><input data-visualizer="opacity" type="number" min="0" max="1" step="0.05" value="${Math.max(0,Math.min(1,finite(v.opacity,.8)))}"></div><div class="pr-prop-actions"><button class="btn btn-primary btn-sm" data-save-visualizer>ビジュアライザーを保存</button><button class="btn btn-secondary btn-sm" data-template-visualizer>チャンネルのテンプレートとして保存</button></div>`}
function visualizerSection(){return `<section class="pr-prop-section pr-visualizer-settings"><h3>オーディオビジュアライザー</h3><p>音声に連動して動画へ焼き込む演出を設定します。プレビューは近似表示です。</p>${visualizerForm()}</section>`}
function renderProperties(){const box=document.getElementById('prProperties');if(!box||!_atlModel)return;const sel=window._atlFilmora?.selected;if(!sel){box.innerHTML='<div class="pr-empty">タイムラインでクリップを選択してください</div>'+visualizerSection();bindProperties(box,null);return}if(sel.kind==='now-playing'){box.innerHTML='<section class="pr-prop-section"><h3>楽曲名表示</h3><p>再生中の曲名オーバーレイを調整します。</p>'+nowPlayingForm()+'</section>'+visualizerSection();bindProperties(box,null);return}const item=resolveSelection(sel);if(!item){window._atlFilmora.selected=null;box.innerHTML='<div class="pr-empty">タイムラインでクリップを選択してください</div>'+visualizerSection();bindProperties(box,null);return}let specific='',title='クリップ設定',help='選択中のクリップを調整します。';if(item.kind==='audio'){title='音声設定';help='音量と曲のつなぎ方を調整します。';specific=`<div class="pr-prop-row"><span>音量ゲイン</span><input data-prop="gain_db" type="number" min="-60" max="12" step="0.1" value="${Math.max(-60,Math.min(12,finite(item.row.gain_db)))}"></div>`+transitionProperties(item.row)}else if(item.kind==='visual'){title='映像設定';help='表示時間と映像のつなぎ方を調整します。';specific=transitionProperties(item.row)}else{title='文字設定';help='文章、配置、見た目を調整します。';specific=textProperties(item.row)}box.innerHTML=`<section class="pr-prop-section"><h3>基本情報</h3><p>種別と時間を確認します。</p>${commonProperties(item)}</section><section class="pr-prop-section"><h3>${title}</h3><p>${help}</p>${specific}</section><div class="pr-prop-actions"><button class="btn btn-primary btn-sm" data-save-props>適用</button></div>${visualizerSection()}`;bindProperties(box,item)}
function nowPlayingForm(){const n=_atlModel.now_playing||{};return `<div class="pr-prop-row"><span>楽曲名表示</span><input data-now="enabled" type="checkbox" ${n.enabled?'checked':''}></div><div class="pr-prop-row"><span>表示秒数</span><input data-now="intro_seconds" type="number" min="0" step="0.1" value="${Number(n.intro_seconds||8)}"></div><div class="pr-prop-row"><span>位置</span><select data-now="position"><option value="top-left">左上</option><option value="top-center">上中央</option><option value="top-right">右上</option><option value="bottom-left">左下</option><option value="bottom-center" ${n.position==='bottom-center'?'selected':''}>下中央</option><option value="bottom-right">右下</option></select></div><div class="pr-prop-actions"><button class="btn btn-primary btn-sm" data-save-now>楽曲名表示を保存</button></div>`}
function normalizeProp(key,value){if(key==='gain_db')return Math.max(-60,Math.min(12,finite(value)));if(key==='opacity')return Math.max(0,Math.min(1,finite(value,1)));if(key==='size')return Math.max(1,finite(value,48));if(['crossfade_sec','border_width','fade_in','fade_out','margin'].includes(key))return Math.max(0,finite(value));return value}
function readVisualizer(box){const v={};box.querySelectorAll('[data-visualizer]').forEach(x=>v[x.dataset.visualizer]=x.type==='checkbox'?x.checked:x.type==='number'?Number(x.value):x.value);if(v.color){v.color1=v.color;delete v.color}v.color_mode=v.color_mode||(_atlModel?.visualizer?.color_mode)||'gradient';v.width_percent=Math.max(10,Math.min(100,finite(v.width_percent,60)));v.height_px=Math.max(20,Math.min(1080,finite(v.height_px,160)));v.margin=Math.max(0,finite(v.margin,64));v.opacity=Math.max(0,Math.min(1,finite(v.opacity,.75)));return v}
function bindProperties(box,item){const updateDuration=()=>{const start=finite(box.querySelector('[data-prop="start"]')?.value),end=finite(box.querySelector('[data-prop="end"]')?.value,start),out=box.querySelector('[data-duration-output]');if(out)out.textContent=`${Math.max(0,end-start).toFixed(2)} 秒`};box.querySelectorAll('[data-prop="start"],[data-prop="end"]').forEach(x=>x.addEventListener('input',updateDuration));const gainInput=box.querySelector('[data-prop="gain_db"]');gainInput?.addEventListener('input',()=>{if(item?.kind==='audio'&&P.currentAudio?._atlClipId===item.row.id)applyPreviewGain(finite(gainInput.value))});box.querySelector('[data-save-props]')?.addEventListener('click',()=>{if(!item)return;const before=clone(_atlModel),row=item.row;box.querySelectorAll('[data-prop]').forEach(x=>{const value=x.type==='number'?Number(x.value):x.value;row[x.dataset.prop]=normalizeProp(x.dataset.prop,value)});if(item.kind!=='audio'&&finite(row.end)<=finite(row.start))row.end=finite(row.start)+.1;if(item.kind==='text'&&item.track?.id==='T1')_atlModel.text_lane=item.track.clips;window.atlCommit(before)});box.querySelector('[data-save-now]')?.addEventListener('click',()=>{const before=clone(_atlModel),n=_atlModel.now_playing||(_atlModel.now_playing={});box.querySelectorAll('[data-now]').forEach(x=>n[x.dataset.now]=x.type==='checkbox'?x.checked:x.type==='number'?Number(x.value):x.value);window.atlCommit(before)});box.querySelector('[data-save-visualizer]')?.addEventListener('click',()=>saveVisualizer(box,false));box.querySelector('[data-template-visualizer]')?.addEventListener('click',()=>saveVisualizer(box,true))}
async function saveVisualizer(box,template){const before=P.visualizerSaved||clone(_atlModel),v=readVisualizer(box);_atlModel.visualizer=v;await window.atlCommit(before);P.visualizerSaved=null;applyVisualizerLayout();bindVisualizerCanvas();if(template){const channelId=window.AutomationStudioContext?.channelId||(typeof _uiChannelId!=='undefined'?_uiChannelId:'');const r=await fetch(`/api/timeline/${encodeURIComponent(_curVideo)}/visualizer-template`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({channel_id:channelId,visualizer:v})});toast(r.ok?'チャンネルテンプレートへ保存しました':'テンプレート保存に失敗しました',r.ok?'s':'e')}}
