function renderPreviewLayers(sec){const canvas=document.querySelector('#atlPreview .atl-preview-canvas');if(!canvas||!_atlModel)return;canvas.querySelectorAll('.atl-preview-video-layer,.atl-free-text-overlay').forEach(x=>x.remove());const time=finite(sec),videos=Array.isArray(_atlModel.video_tracks)?_atlModel.video_tracks.slice(1):[];videos.forEach((track,index)=>{if((_atlModel.track_states?.[track.id]||{}).hidden)return;const segment=(track.segments||[]).find(x=>time>=finite(x.start)&&time<finite(x.end));if(!segment?.image_path)return;const image=document.createElement('img');image.className='atl-preview-video-layer';image.dataset.previewVideoTrack=track.id;image.alt='';image.src=`/api/timeline/${encodeURIComponent(_curVideo)}/image?path=${encodeURIComponent(segment.image_path)}`;image.style.zIndex=String(11+Math.min(index,8));canvas.append(image)});(_atlModel.text_tracks||[]).forEach(track=>{if((_atlModel.track_states?.[track.id]||{}).hidden)return;(track.clips||[]).filter(clip=>clip.kind==='free_text'&&time>=finite(clip.start)&&time<finite(clip.end)).forEach(clip=>{const text=document.createElement('div');text.className=`atl-free-text-overlay ${previewPositionClass(clip.position)}`;text.dataset.previewTextTrack=track.id;text.textContent=clip.text||'テキストを入力';text.style.cssText=`font-size:${Math.max(12,finite(clip.size,48)/3)}px;color:${clip.color||'#fff'};opacity:${Math.max(0,Math.min(1,finite(clip.opacity,1)))};-webkit-text-stroke:${Math.max(0,finite(clip.border_width,2)/3)}px ${clip.border_color||'#000'};font-family:${JSON.stringify(clip.font_name||'Hiragino Sans')}`;canvas.append(text)})})}
function normalizeVisualizerUi(){const v=_atlModel?.visualizer;if(!v)return;v.color=v.color1||v.color||'#ffffff';v.color2=v.color2||'#7c3aed';v.color_mode=v.color_mode||'gradient'}
window.aplApplyLayout=function(){const root=document.getElementById('assemblyTimeline'),preview=document.getElementById('atlPreview');if(root&&preview&&!root.contains(preview))root.prepend(preview);ensureLayout();placePreview();loadAssets();normalizeVisualizerUi();renderProperties();decorateTracks();premiereTrackOrder();refreshNowPlayingLabels();decorateFilmstrips();enhanceConnectionSettings();applyVisualizerLayout();guardLayout()};
const basePlay=window.atlPlayAt;window.atlPlayAt=function(sec){const excluded=new Set(_atlModel?.excluded||[]),clip=(_atlModel?.audio_clips||[]).find(x=>!excluded.has(x.id)&&finite(x.start)<=finite(sec)&&finite(sec)<finite(x.end));basePlay(sec);if(clip&&_atlAudio){_atlAudio._atlClipId=clip.id;_atlAudio._atlGainDb=Math.max(-60,Math.min(12,finite(clip.gain_db)));_atlAudio.addEventListener('play',()=>document.querySelector('.pr-program .pr-spectrum')?.classList.remove('is-idle'));_atlAudio.addEventListener('pause',()=>{document.querySelector('.pr-program .pr-spectrum')?.classList.add('is-idle');if(P.visualMode==='measure')finishSpectrumRecord()},{once:true});_atlAudio.addEventListener('ended',()=>{document.querySelector('.pr-program .pr-spectrum')?.classList.add('is-idle');if(P.visualMode==='measure')finishSpectrumRecord()},{once:true})}setTimeout(()=>{if(clip&&_atlAudio&&connectAnalyser(_atlAudio))startVisualizer()},0)};
window.atlOpenTransition=function(kind,index){window._atlFilmora.selected=kind==='audio'?{kind:'audio',id:_atlModel.audio_clips[index]?.id}:{kind:'visual',index};renderProperties()};
window.atlOpenNowPlaying=function(){window._atlFilmora.selected={kind:'now-playing'};renderProperties();document.querySelector('[data-save-now]')?.scrollIntoView({block:'nearest'})};
function releasePreviewAudio(){stopVisualizer();const audio=typeof _atlAudio!=='undefined'?_atlAudio:null;if(audio){try{audio.pause()}catch{}try{audio.removeAttribute('src');audio.load()}catch{}disconnectAudioGraph(audio)}try{P.analyser?.disconnect()}catch{}P.audioContext?.close?.().catch(()=>{});P.currentAudio=null;P.analyser=null;P.audioContext=null;P.destinationConnected=false;if(typeof _atlAudio!=='undefined')_atlAudio=null;if(window._atlFilmora)window._atlFilmora.direction=0;document.querySelectorAll('[data-atl-play]').forEach(button=>{button.classList.remove('is-playing');button.setAttribute('aria-pressed','false');button.setAttribute('aria-label','再生');button.title='再生';if(button.closest('.pr-program-transport'))button.innerHTML=transportSvg.play;else button.textContent='再生'})}
document.addEventListener('visibilitychange',()=>{if(document.hidden)releasePreviewAudio();else applyVisualizerLayout()});
addEventListener('hashchange',releasePreviewAudio);
