document.addEventListener('change',e=>{const input=e.target.closest?.('#prProperties [data-visualizer]'),box=input?.closest('#prProperties');if(!input||!box||!_atlModel)return;if(!P.visualizerSaved)P.visualizerSaved=clone(_atlModel);_atlModel.visualizer=readVisualizer(box);applyVisualizerLayout();if(_atlModel.visualizer.enabled)startVisualizer();else stopVisualizer()},true);
