Object.assign(window,{prDropAsset:dropAsset,prRenderProperties:renderProperties,atlAddTextClip:addTextClip,aplTrackEnabled:id=>!trackDisabled(id),aplTransportSvg:transportSvg,aplReleasePreviewAudio:releasePreviewAudio,aplApplyVisualizerLayout:applyVisualizerLayout,aplPremiereTrackOrder:premiereTrackOrder});
if(typeof _atlModel!=='undefined'&&_atlModel&&typeof _curVideo!=='undefined'&&_curVideo&&document.getElementById('assemblyTimeline'))window.renderAssemblyTimeline(_curVideo);
